export function computeChannelGainsG(balance: number): number[] {
  let b = balance
  if (b < -1) {
    b = -1
  } else if (b > 1) {
    b = 1
  }
  const left = b <= 0 ? 1 : 1 - b
  const right = b >= 0 ? 1 : 1 + b
  const lr = Math.round(left * 1000) / 1000
  const rr = Math.round(right * 1000) / 1000
  return [lr, rr]
}

