export function dedupeKeepOrderG(items: number[]): number[] {
  const seen: number[] = []
  const result: number[] = []
  for (let i = 0; i < items.length; i++) {
    const v = items[i]
    if (seen.indexOf(v) < 0) {
      seen.push(v)
      result.push(v)
    }
  }
  return result
}

