export function mixBandGainsG(bands: number[], preamp: number): number {
  let sum = preamp
  for (let i = 0; i < bands.length; i++) {
    sum += bands[i]
  }
  const MIN = -24
  const MAX = 24
  if (sum < MIN) {
    return MIN
  }
  if (sum > MAX) {
    return MAX
  }
  return Math.round(sum * 10) / 10
}

