export function formatByteSizeG(bytes: number): string {
  const units: string[] = ['B', 'KB', 'MB', 'GB']
  let i = 0
  let v = bytes
  while (v >= 1024 && i < units.length - 1) {
    v = v / 1024
    i++
  }
  return v.toFixed(1) + units[i]
}

