export function compareSemverG(local: string, remote: string): number {
  const a = local.split('.')
  const b = remote.split('.')
  const len = Math.max(a.length, b.length)
  for (let i = 0; i < len; i++) {
    const x = i < a.length ? parseInt(a[i], 10) : 0
    const y = i < b.length ? parseInt(b[i], 10) : 0
    if (x > y) {
      return 1
    }
    if (x < y) {
      return -1
    }
  }
  return 0
}

