export function isPalindromeG(text: string): boolean {
  const s = text.toLowerCase()
  let i = 0
  let j = s.length - 1
  while (i < j) {
    if (s.charAt(i) !== s.charAt(j)) {
      return false
    }
    i++
    j--
  }
  return true
}

